// AI document scanner (same Worker /scan + comprobante.tsx use). Reads a
// Zelle/wire/deposit screenshot and extracts amount/date/sender/ref/bank so
// Ángeles confirms instead of typing. Mirrors aiReadDocument() in
// tesoreria/comprobante/page.tsx — kept local because that one is nested in a
// component and not importable.
const COMPROBANTE_WORKER = 'https://autocore-comprobante.sano-franco.workers.dev'

function fileToBase64(file: File): Promise<string> {
  return new Promise((res, rej) => {
    const r = new FileReader()
    r.onload = () => res(String(r.result).split(',')[1])
    r.onerror = () => rej(new Error('read failed'))
    r.readAsDataURL(file)
  })
}

// Venezuelan number -> E.164 (+58XXXXXXXXXX). null if not a valid VE number.
function normalizeVePhone(raw: string): string | null {
  if (!raw) return null
  let p = String(raw).replace(/\D/g, '')
  if (!p) return null
  if (p.length === 12 && p.startsWith('58')) p = p.slice(2)
  else if (p.length === 11 && p.startsWith('0')) p = p.slice(1)
  if (p.length === 10 && (p[0] === '4' || p[0] === '2')) return '+58' + p
  return null
}

export interface ReceiptRead {
  ok: boolean
  monto_leido?: number
  fecha?: string | null
  referencia?: string | null
  banco?: string | null
  titular_destino?: string | null
  cuenta_ultimos4?: string | null
  remitente?: string | null
  motivo?: string | null
}

// Reads a payment receipt (Zelle/wire/transfer/deposit). Distinct prompt from
// the CDO/Factura scanner — looks for money fields, not a VIN.
// 2026-06-12: also extracts the RECIPIENT (titular de la cuenta destino) and
// last-4 — the bank name alone can't distinguish Motocentro vs Roframi (both
// at BofA), which caused ING-0023 to land on the wrong account.
async function aiReadReceipt(file: File): Promise<ReceiptRead> {
  try {
    const base64 = await fileToBase64(file)
    const isPdf = file.type === 'application/pdf'
    const prompt = `Esta es una constancia de pago: Zelle, transferencia, wire o depósito bancario. Devuelve SOLO un objeto JSON, sin markdown ni texto adicional:
{"monto": <número USD>, "fecha": "<YYYY-MM-DD o null>", "banco": "<banco receptor o null>", "titular_destino": "<nombre del DESTINATARIO/beneficiario de la cuenta que RECIBE el dinero, o null>", "cuenta_ultimos4": "<últimos 4 dígitos de la cuenta destino si son visibles, o null>", "remitente": "<nombre de quien envía o null>", "referencia": "<número de referencia/confirmación o null>"}
Extrae el monto real del documento. Si ves "Zelle", "ACH", "wire" o un confirmation #, inclúyelo en referencia.
IMPORTANTE: titular_destino es quien RECIBE (ej. "Roframi Management LLC", "Motocentro"), NO quien envía. Si el destinatario no es visible o no estás seguro, usa null — nunca adivines.`
    const contentBlock = isPdf
      ? { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: base64 } }
      : { type: 'image', source: { type: 'base64', media_type: file.type || 'image/jpeg', data: base64 } }
    const resp = await fetch(COMPROBANTE_WORKER, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        messages: [{ role: 'user', content: [contentBlock, { type: 'text', text: prompt }] }],
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 600,
      }),
    })
    const data = await resp.json()
    const textBlock = (data.content || []).find((b: any) => b.type === 'text')
    const raw = (textBlock?.text || '').replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim()
    const parsed = JSON.parse(raw)
    const monto = Number(parsed.monto) || 0
    return {
      ok: true,
      monto_leido: monto > 0 ? monto : undefined,
      fecha: parsed.fecha || null,
      referencia: parsed.referencia || null,
      banco: parsed.banco || null,
      titular_destino: parsed.titular_destino || null,
      cuenta_ultimos4: parsed.cuenta_ultimos4 || null,
      remitente: parsed.remitente || null,
    }
  } catch (e: any) {
    return { ok: false, motivo: 'No se pudo leer el comprobante: ' + (e?.message || 'error') }
  }
}

// Map the AI-read recipient → our account code. Recipient name wins, then
// last-4, then bank name ONLY when unambiguous (BofA covers two accounts, so
// BofA alone resolves to null → the user must pick). Returns null = unknown.
function resolveCuentaDestino(r: ReceiptRead): string | null {
  const titular = (r.titular_destino || '').toLowerCase()
  const banco = (r.banco || '').toLowerCase()
  const last4 = (r.cuenta_ultimos4 || '').replace(/[^0-9]/g, '')
  // 1. Recipient name — strongest signal.
  if (titular.includes('rofram')) {
    return banco.includes('regions') ? 'roframi_regions' : 'roframi'
  }
  if (titular.includes('motocentro')) return 'motocentro'
  // 2. Last-4 of the destination account.
  if (last4 === '0481') return 'motocentro'
  if (last4 === '7252') return 'roframi'
  // 3. Bank name — only where one account exists at that bank.
  if (banco.includes('mercantil') || banco.includes('panam')) return 'panama'
  if (banco.includes('regions')) return 'roframi_regions'
  // BofA / unknown bank: ambiguous (Motocentro AND Roframi are both BofA).
  return null
}

// ── WhatsApp notifications (Tesorería) ──────────────────────────────────────
// Fire-and-forget POST to autocore-whatsapp /notify-tesoreria after a
// successful DB transition. Non-blocking, non-fatal: if the worker is down,
// the DB write has already happened so the user's action stands. We just
// don't get the WhatsApp ping.
const WHATSAPP_WORKER = 'https://autocore-whatsapp.sano-franco.workers.dev'

function notifyTesoreria(payload: Record<string, any>) {
  try {
    fetch(WHATSAPP_WORKER + '/notify-tesoreria', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      keepalive: true, // finish the request even if the page navigates away
    }).catch(() => { /* silent — never break the user flow */ })
  } catch { /* silent */ }
}

// ── Client receipt (WhatsApp PDF) ───────────────────────────────────────────
// Fire-and-forget POST to autocore-whatsapp /send-receipt after a successful
// ingreso. The worker mints the REC-… number, builds the PDF, hosts it, and
// only sends if the linked client has a phone on file. Non-blocking: the DB
// write has already succeeded, so a worker hiccup never costs the registration.
function sendReceipt(payload: Record<string, any>) {
  try {
    fetch(WHATSAPP_WORKER + '/send-receipt', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      keepalive: true,
    }).catch(() => { /* silent */ })
  } catch { /* silent */ }
}

