  const [cdSearch, setCdSearch]   = useState('')
  const [cdResults, setCdResults] = useState<any[]>([])
  const [cdSel, setCdSel]         = useState<any | null>(null)
  const [cdBusy, setCdBusy]       = useState(false)
  const [clienteNombre, setClienteNombre] = useState('')
